class Solution {
public:
    int numSub(string s) {
        int MOD = 1e9 + 7;
        int count = 0;
        int total = 0;
        for (char c : s) {
            if (c == '1') {
                count++;
            } else {
                total = (total + (count * (count + 1)) / 2) % MOD;
                count = 0;
            }
        }
        total = (total + (count * (count + 1)) / 2) % MOD;
        return total;
    }
};

